from flask import Flask, render_template, request, redirect, url_for, session
import requests
import json

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret_key_here'

# Client ID and secret for OpenID Connect provider
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'

# Authorization server URL for OpenID Connect provider
AUTH_SERVER_URL = 'https://your_openid_provider_authorization_server.com/authorize'

# Token endpoint URL for OpenID Connect provider
TOKEN_ENDPOINT_URL = 'https://your_openid_provider_token_endpoint.com/token'

# User info endpoint URL for OpenID Connect provider
USER_INFO_ENDPOINT_URL = 'https://your_openid_provider_user_info_endpoint.com/.well-known/openid-configuration'

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login')
def login():
    params = {
        'client_id': CLIENT_ID,
        'response_type': 'code',
        'redirect_uri': url_for('callback', _external=True),
        'scope': 'openid profile email'
    }
    return redirect(f'{AUTH_SERVER_URL}?{dict_to_query_string(params)}')

def dict_to_query_string(dictionary):
    return '&'.join([f'{key}={value}' for key, value in dictionary.items()])

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if code:
        token_response = requests.post(
            TOKEN_ENDPOINT_URL,
            headers={'Content-Type': 'application/x-www-form-urlencoded'},
            data={
                'grant_type': 'authorization_code',
                'code': code,
                'redirect_uri': url_for('callback', _external=True),
                'client_id': CLIENT_ID,
                'client_secret': CLIENT_SECRET
            }
        )
        token_response = json.loads(token_response.content)
        id_token = token_response['id_token']
        user_info_url = json.loads(requests.get(USER_INFO_ENDPOINT_URL).content)['userinfo_endpoint']
        user_info_response = requests.post(
            user_info_url,
            headers={'Content-Type': 'application/x-www-form-urlencoded'},
            data={
                'grant_type': 'urn:ietf:params:oauth:grant-type:token',
                'code': code,
                'redirect_uri': url_for('callback', _external=True),
                'client_id': CLIENT_ID,
                'client_secret': CLIENT_SECRET
            }
        )
        user_info = json.loads(user_info_response.content)
        session['username'] = user_info['name']
        return render_template('logged_in.html')
    else:
        return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)